import { Alert, Badge, Button, ButtonGroup, Card, Chip, CircularProgress, Container, Divider, Grid2, Snackbar, Stack, SwipeableDrawer, TextField, Tooltip, Typography } from "@mui/material";
import { useEffect, useState } from "react";
import { CalculateDays } from "./RemainItem";
import PrintDisabledOutlinedIcon from '@mui/icons-material/PrintDisabledOutlined';
import WatchLaterOutlinedIcon from '@mui/icons-material/WatchLaterOutlined';
import DangerousOutlinedIcon from '@mui/icons-material/DangerousOutlined';
import API from "../../../API/API";


function PropertyCard({label,value,adLabel,props}) {

    return (
        <Card variant="outlined">
                            <Stack direction="column" justifyContent="space-between">
                                <Typography
                                    variant="h5"
                                    sx={{
                                        fontSize: {xs: '16px'}
                                    }}
                                >
                                    {label}
                                </Typography>
                                <Stack direction="row" justifyContent="center" alignItems="end" textAlign="center" spacing={{xs: 0.1, sm: 0.5, md: 1, lg: 1}}>
                                <Typography
                                    variant="h3"
                                    sx={{
                                        fontSize: {xs: '18px', sm: '32px', md: '42px', lg: '42px'}
                                    }}
                                >
                                    {value.toFixed(2)}
                                </Typography>
                                {adLabel && <Typography
                                    variant="h6"
                                    sx={{
                                        fontSize: {xs: '10px', sm: '16px', md: '22px', lg: '22px'}
                                    }}
                                >
                                    {adLabel}
                                </Typography>}
                                </Stack>
                            </Stack>
            </Card>
    )
}

function OldCount(item) {

    var old = CalculateDays(item.ConfirmedDate) > 7;

    return (<Tooltip arrow title={!old ? "Актуальный" : "Не актуальный"}><DangerousOutlinedIcon color={!old ? "success" : "error"} /></Tooltip>);
}

function NewCount(item) {

    var isNew = CalculateDays(item.AddedDate) <= 2;


    return (
        <Tooltip arrow title={isNew ? "Новый остаток" : "Старый остаток"}>
            <WatchLaterOutlinedIcon color={isNew ? "success" : "warning"}/>
        </Tooltip>)
}

function CalculateS(item) {

    var S = 0;
    for(var remain of item.List) {
        S += remain.sizeX*remain.sizeY
    }


    return (<Chip label={`Общая площадь: ${S.toFixed(2)} м2`} variant="outlined" />)
}

function IsPrinted(item) {

    return (
        <Tooltip arrow title={item.Printed ? "Распечатан" : "Не распечатан"}><PrintDisabledOutlinedIcon color={item.Printed ? "success" : "error"} /></Tooltip>
      )
}

export default function RemainListItem({item,data,onRemoved,...props}) {

    const [price,setPrice] = useState('');
    const [shopPrintDrawer,setPrintDrawer] = useState(false);
    const [printing,setPrinting] = useState(false);
    const [showRemoveDrawer,setRemoveDrawer] = useState(false);
    const [selled,setSelled] = useState(false);

    const [notificate,setNotificate] = useState({
        show: false,
        message: ""
    });

    useEffect(() => {

    },[item,data])

    const sendNotification = (message) => {
        setNotificate({
            show: true,
            message: message
        })
    }

    const onPrintClicked = async () => {
        try {
            setPrinting(true);
            let remain = [{
                lm_code: data.lm_code,
                Name: data.Name,
                price: price,
                item_type: data.item_type,
                Overlock: data.Overlock || null,
                List: [
                    item
                ]
            }];
        let response = await API.PrintOneRemain(remain);
        const file = new Blob([response.data],{type: "application/pdf"});
        const fileURL = URL.createObjectURL(file);
        const pdfWindow = window.open();
        pdfWindow.location.href = fileURL;
        setPrinting(false);
        setPrintDrawer(false);
        item.Printed = true;
        sendNotification("Бланк остатка успешно сформирован")
        }
        catch(e) {

        }
    }

    const onSellClicked = async () => {
        try {
            let response = await API.SellRemain(item.id);
            if(response.status == 200) {
                item.selled = true;
                setSelled(true);
                sendNotification("Остаток продан")
            }
        }
        catch(e) {

        }
    }

    const handleRemove = () => {
        API.RemoveRemain(item.id);
        data.List = data.List.filter(d => d.id != item.id);
        setRemoveDrawer(false);
        onRemoved(item.id);
    }

    return (
        <>
        <Card variant="outlined" sx={{
            backgroundColor:'#fcfcfc'
        }}>
            <Stack direction="column" padding={1} spacing={1}>
                <Stack direction="row" spacing={1} justifyContent="space-between">
                    <Typography
                        variant="caption"
                    >
                        {(new Date(item.AddedDate).toLocaleString('ru-RU'))}
                    </Typography>
                    <Typography
                        variant="caption"
                    >
                        Создал: {item.CreatedByName}
                    </Typography>
                </Stack>
                <Divider/>
                <Typography textAlign='center' variant="h5">
                    Размеры
                </Typography>
                <Grid2 container columns={3} spacing={2}>
                    <Grid2 size={1} justifyContent="center" textAlign="center">
                        <PropertyCard label="Ширина" value={item.sizeX} adLabel="м"/>
                    </Grid2>
                    <Grid2 size={1} justifyContent="center" textAlign="center">
                        <PropertyCard label="Длина" value={item.sizeY} adLabel="м"/>
                    </Grid2>
                    <Grid2 size={1} justifyContent="center" textAlign="center">
                        <PropertyCard label="Площадь" value={item.sizeY*item.sizeX} adLabel="м2"/>
                    </Grid2>
                </Grid2>
                <Typography textAlign='center' paddingTop={1} variant="h5">
                    Оверлок
                </Typography>
                {item.Overlock ? (
                <Grid2 container columns={3} spacing={2}>
                    <Grid2 size={1} justifyContent="center" textAlign="center">
                        <PropertyCard label="Длина" value={item.Overlock.meters*1} adLabel="п.м."/>
                    </Grid2>
                    <Grid2 size={1} justifyContent="center" textAlign="center">
                        <PropertyCard label="Цена" value={item.Overlock.price*1} adLabel="р"/>
                    </Grid2>
                    <Grid2 size={1} justifyContent="center" textAlign="center">
                        <PropertyCard label="Сумма" value={item.Overlock.meters*item.Overlock.price} adLabel="р"/>
                    </Grid2>
                </Grid2>) : <Typography textAlign='center'>Нет</Typography>}
                <Divider/>
                    <Stack direction="row" alignContent='center' alignItems='center' width='100%' justifyContent="center" spacing={1}>
                        {OldCount(item)}
                        {IsPrinted(item)}
                        {NewCount(item)}
                    </Stack>
                <Divider/>
                <Stack direction="row" justifyContent="center">
                    <ButtonGroup fullWidth>
                        <Button color="success" variant="outlined" onClick={onSellClicked} disabled={selled} fullWidth>Продать</Button>
                        <Button color="inherit" variant="outlined" disabled={selled} onClick={() => setPrintDrawer(true)} fullWidth>Печать</Button>
                        <Button color="error" variant="outlined" onClick={() => setRemoveDrawer(true)} disabled={selled} fullWidth>Удалить</Button>
                    </ButtonGroup>
                </Stack>
            </Stack>
        </Card>
        <SwipeableDrawer
            
            open={shopPrintDrawer}
            ModalProps={{
                keepMounted: false,
                
            }}
            anchor="bottom"
            disableSwipeToOpen={true}
            onClose={() => setPrintDrawer(false)}
        >
                <Stack direction='column' justifyContent='center' alignItems='center' padding={2} spacing={0.5}>
                    <Typography
                        variant="h5"
                        textAlign='center'
                    >
                        Печать остатка
                    </Typography>
                    <Typography
                        variant="h6"
                        textAlign='center'
                    >
                        {data?.Name}
                    </Typography>
                    <Divider />
                    <Typography
                        variant="body1"
                        textAlign='center'
                    >
                        Для подолжения введите цену за квадратный метр.
                    </Typography>
                    
                    <TextField type="number" label="Цена остатка за м2" value={price} onChange={e => setPrice(e.target.value)} sx={{width: {xs: '100%', sm:'100%',md:'50%',lg:'50%'}}} size="small"/>
                    <Button variant="contained" disabled={price <= 0 || printing} onClick={onPrintClicked} sx={{width: {xs: '100%', sm:'100%',md:'50%',lg:'50%'}}}>
                        {!printing ? "Сформировать остаток" : <CircularProgress size='24px'/> }
                    </Button>
                    <Button variant="secondary" 
                    sx={{width: {xs: '100%', sm:'100%',md:'50%',lg:'50%'}}}
                    onClick={() => {
                        var w = window.open(`https://ekaterinburg.lemanapro.ru/search/?q=${data.lm_code}`).focus();
                        }}>Проверить цену на сайте</Button>
                </Stack>
        </SwipeableDrawer>

        <SwipeableDrawer
            
            open={showRemoveDrawer}
            ModalProps={{
                keepMounted: false,
            }}
            anchor="bottom"
            disableSwipeToOpen={true}
            onClose={() => setRemoveDrawer(false)}
        >
                <Stack direction='column' justifyContent='center' alignItems='center' padding={2} spacing={0.5}>
                    <Typography
                        variant="h5"
                        textAlign='center'
                        color='error'
                    >
                        УДАЛЕНИЕ ОСТАТКА
                    </Typography>
                    <Typography
                        variant="h6"
                        textAlign='center'
                    >
                        {data?.Name}
                    </Typography>
                    <Divider />
                    <Typography
                        variant="body1"
                        textAlign='center'
                    >
                        Вы собираетесь удалить остаток из системы.<br/>
                        Если вы продали остаток - нажмите ПРОДАТЬ.
                    </Typography>
                    
                    <Button variant="contained" color="error" onClick={() => {handleRemove()}} sx={{width: {xs: '100%', sm:'100%',md:'50%',lg:'50%'}}}>
                        УДАЛИТЬ
                    </Button>
                    <Button variant="secondary" 
                    sx={{width: {xs: '100%', sm:'100%',md:'50%',lg:'50%'}}}
                    onClick={() => {setRemoveDrawer(false)}}>Отмена</Button>
                </Stack>
        </SwipeableDrawer>

        <Snackbar open={notificate.show} autoHideDuration={5000} onClose={() => setNotificate({show: false, message: notificate.message})}>
            <Alert
                severity="success"
                variant="filled"
                sx={{ width: '100%' }}
            >
                {notificate.message}
            </Alert>
        </Snackbar>
        </>
    )
}