import { Button, Container, Divider, Grid2, Typography } from "@mui/material";
import { useNavigate } from "react-router-dom";




export default function ServiceDisabled(props) {

    const navigator = useNavigate();

    return (
        <Container
            fixed
        >
            <Grid2 container padding={2} direction="column" alignItems="center" justifyContent="center" textAlign='center'
                sx={{height: '80vh'}}
            >
                <Typography
                    variant="h2"
                    sx={{
                        fontSize: {xs:'20px',sm:'24px',md:'42px',lg:'52px'}
                    }}
                >
                    Сервис отключен.
                </Typography>
                <Typography
                    variant="body2"
                    sx={{
                        fontSize: {xs:'12px',sm:'18px',md:'24px',lg:'32px'}
                    }}
                >
                    На данный момент сервис не работает.<br/>Возможно, он не востребован или не завершен.
                </Typography>
                <Divider />
                <Button onClick={() => navigator("/")}>В главное меню</Button>
            </Grid2>
        </Container>
    )

}