import { Box, Button, CircularProgress, Divider, Grid2, List, ListItem, Stack, TextField, Typography } from "@mui/material";
import { useEffect } from "react";
import { UnprintedElement } from "./UnprintedElement";



const Loading = () => {
    return (
        <Grid2 size={12}>
            <Box flex='column' justifyItems='center' sx={{width: '100%'}}>
                    <CircularProgress />
                    <Typography variant="h6" >
                    Загрузка...
                    </Typography>
            </Box>
        </Grid2>
    )
}

const NoData = () => {
    return (
        <Grid2 size={12}>
            <Box flex='column' justifyItems='center' sx={{width: '100%'}}>
                    <Typography variant="h6" >
                    Не распечатанных остатков нет
                    </Typography>
            </Box>
        </Grid2>
    )
}

export function PrintList({data,onChange,...props}) {

    useEffect(() => {
    },[data]);

    return (
        <>
            { data == null ? <Loading /> : 
                <>
                {data.length <= 0 && <NoData />}
                {data.length >= 0 && 
                (data.map((item,index) => (
                    <UnprintedElement onItemPriceChange={onChange} element={item} />
                )))}
                </>
                
            }
        </>
    )
}