import { Alert, Button, Card, Collapse, Divider, Grid2, LinearProgress, Stack, Typography } from "@mui/material";
import { PrintList } from "./Components/PrintList";
import { useEffect, useRef, useState } from "react";
import API from "../../API/API";


const HowToUse = () => {return (
    <>
        <Card padding variant="outlined">
            <Stack direction='column' padding={2} spacing={1}>
                <Typography variant="h4" component='h4'>
                    Как пользоваться
                </Typography>
                <Typography variant="body1" component='p'>
                    Ниже предоставлен список новых остатков, бланки которых еще не были распечатаны. Перед печатью необходимо указать текущую цену
                    за остаток. Для этого воспользуйся кнопкой "Проверить цену на сайте".
                </Typography>
                <Alert severity="info">
                    Пока все цены не будут указаны, сформировать бланки не получится.
                </Alert>
            </Stack>
        </Card>
    </>
)}

export function PrintPage(props) {

    const progressRef = useRef(null);
    const [sidebarTop, setSidebarTop] = useState(undefined);
    const [ready,setReady] = useState(false);    
    const [unprintedList,setList] = useState(null);

    const [readyPercent,setReadyPercent] = useState(0);
    const [formedPercent,setformedPercent] = useState(0);

    const [isBusy,setBusy] = useState(false);

    const sendPrint = async () => {
        try {
            let response = await API.PrintOneRemain(unprintedList);
            const file = new Blob([response.data],{type: "application/pdf"});
            const fileURL = URL.createObjectURL(file);
            const pdfWindow = window.open();
            pdfWindow.location.href = fileURL;
            setReady(false);
            setList([]);
        }
        catch(e) {

        }
    }

    const calculateReady = (array) => {
        if(array.length == 0) return setReadyPercent(0);
        var readyCount = 0;
        
        for(let item of array) {
            console.log(item);
            if(item.price != undefined) {
                if(item.price > 0) {
                    readyCount+=1;
                }
            }
        }
        setReadyPercent((readyCount / unprintedList.length) * 100);
        if((readyCount / unprintedList.length) * 100 >= 100) {
            setReady(true);
        }
        else {
            setReady(false);
        }
    }

    const onChange = (element,price) => {
        var newArray = [...unprintedList];
        for(let elem of newArray) {
            if(elem.lm_code == element.lm_code) {
                elem.price = price;
            }
        }
        calculateReady(newArray);
        setList(newArray);
    }

    useEffect(() => {
        
        const sidebarEl = progressRef.current.getBoundingClientRect();
        setSidebarTop(sidebarEl.top);
        (async () => {
            try {
                let data = await API.RequestUnprinted();
                setList(data);
            }
            catch(e) {
                console.log(e);
            }
        })();
      }, []);

    useEffect(() => {
        if (!sidebarTop) return;
        
        window.addEventListener("scroll", isSticky);
        return () => {
          window.removeEventListener("scroll", isSticky);
        };
      }, [sidebarTop]);
    
      const isSticky = (e) => {
        const sidebarEl = progressRef.current;
        const scrollTop = window.scrollY;
        if (scrollTop >= sidebarTop - 70) {
          sidebarEl.classList.add("progress-sticky");
        } else {
          sidebarEl.classList.remove("progress-sticky");
        }
      };

    return (
        
        <Grid2 container columns={12} spacing={1}>
            <Grid2 size={12} padding={1}>
                <HowToUse />
            </Grid2>
            <Grid2 size={12} padding={1} sx={{position: '-webkit-sticky',
        position: 'sticky',zIndex: 5}}>
                <Card padding variant="outlined" ref={progressRef}>
                    <Stack direction='column' padding={2} spacing={1}>
                        <Typography variant="h6" component='h4'>
                            Прогресс
                        </Typography>
                        <Typography variant="body1" component='p'>
                            <LinearProgress value={readyPercent} color={ready ? "success" : "primary"} valueBuffer={readyPercent} variant="buffer" />
                        </Typography>
                        <Collapse in={ready}>
                            <Button fullWidth variant='contained' color="success" onClick={() => sendPrint()}>Сформировать</Button>
                        </Collapse>
                    </Stack>
                </Card>
            </Grid2>
            <Divider sx={{width: '100%'}}/>
            
            <PrintList data={unprintedList} onChange={onChange} />
        </Grid2>
    );
}