import { Box, Card, CardContent, CircularProgress, Typography } from "@mui/material";
import { BarChart } from "@mui/x-charts";
import { useEffect } from "react"

const monthNames = [
    "Январь",
    "Февраль",
    "Март",
    "Апрель",
    "Май",
    "Июнь",
    "Июль",
    "Август",
    "Сентябрь",
    "Октябрь",
    "Ноябрь",
    "Декабрь",
];

export function ValueChartData({data,label,...props}) {

    useEffect(() => {
    },[data]);

    return (
        <Card variant="outlined">
            <CardContent>
                <Typography variant="h6">
                    {label}
                </Typography>
                {data == null ? <Box sx={{minHeight: ""}} display="flex-column" justifyItems="center" alignContent="center">
                    <CircularProgress />
                </Box>
                :
                <>
                    <Typography variant="h4">
                        {data}
                    </Typography>
                </>}
            </CardContent>
        </Card>
    )
}