import { Backdrop, Box, Card, CircularProgress, Container, Divider, Grid2, Stack, Typography } from "@mui/material";
import { useEffect, useState } from "react";
import { GetRemainType } from "./RemainItem";
import RemainListItem from "./RemainListItem";




export default function RemainFullInfo({remainData,onItemRemove,...props}) {

    const [loading,setLoading] = useState(false);

    useEffect(() => {
        if(remainData == null) return;
        setLoading(true);
        setTimeout(() => {
            setLoading(false);
        },100)
    },[remainData]);

    const onRemove = (id) => {
        onItemRemove(id);
        //remainData.List = remainData.List.filter(d => d.id == id);
    }

    return (
        <>
            <Backdrop
                sx={(theme) => ({ color: '#fff', zIndex: theme.zIndex.drawer + 1 })}
                open={loading}
                >
                <CircularProgress color="inherit" />
            </Backdrop>
            {remainData == null || loading ? <></> : (
            <Grid2 container direction="column" paddingTop={1} columns={12}>
                <Typography
                    variant="h5"
                    component="p"
                >
                    {remainData.Name}
                </Typography>
                <Divider />
                <Typography
                    variant="caption"
                >
                    <Stack direction="row" sx={{
                        justifyContent: "space-between",
                        alignItems: "center",
                        padding: 0.5
                    }}>
                        <span>LM: {remainData.lm_code}</span>  
                        <span>Тип остатка: {GetRemainType(remainData.item_type)}</span>  
                    </Stack>
                </Typography>
                <Container>
                <Grid2 container columns={12} paddingTop={2} spacing={1}>
                    <Box maxHeight="70vh" width={'100%'} sx={{overflowX: 'none', overflowY: 'auto'}}>
                        <Stack container direction="column" spacing={1}>
                            {remainData.List.map((item) => 
                                <RemainListItem key={item.id} item={item} data={remainData} onRemoved={onRemove} />
                            )}
                        </Stack>
                    </Box>
                </Grid2>
                </Container>
            </Grid2>)}
        </>
    );
}