import { Badge, Box, Card, CardActionArea, CardContent, CardMedia, Container, Grid, Grid2, Paper, Typography } from "@mui/material";
import { useNavigate } from "react-router-dom";



export default function MenuButton({to, img,label,badgeContent, ...props}) {

    const navigator = useNavigate();

    const handleClick = (e) => {
        navigator(to);
    }

    if(!badgeContent) {
    return (
            <Card
            sx={{
                backgroundColor: "#fcfcfc"
            }}
                variant="outlined"
            >
                <CardActionArea onClick={handleClick}>
                    <Grid2
                        container
                        direction="column"
                        sx={{
                            height: {xs: "100px", sm: "200px", md: "250px", lg: "300px"},
                            width: {xs: "100px", sm: "200px", md: "250px", lg: "300px"},
                            padding: {xs: 1, sm:4}
                        }}
                        justifyContent="space-between"
                        alignContent="flex-start"
                        
                    >
                        <img src={img} height="50%" width="50%" />
                        <Typography
                            variant="h4"

                            sx = {{
                                fontSize: {xs: "11px", sm: "16px", md: "24px", lg: "32px"}
                            }}
                        >
                            
                            {label}
                        </Typography>
                    </Grid2>
                </CardActionArea>
            </Card>
        )
    }
    else {
        return (
                <Card
                sx={{
                    backgroundColor: "#fcfcfc"
                }}
                    variant="outlined"
                >
                    <CardActionArea onClick={handleClick}>
                        <Grid2
                            container
                            direction="column"
                            sx={{
                                height: {xs: "100px", sm: "200px", md: "250px", lg: "300px"},
                                width: {xs: "100px", sm: "200px", md: "250px", lg: "300px"},
                                padding: {xs: 1, sm:4}
                            }}
                            justifyContent="space-between"
                            alignContent="flex-start"
                            
                        >
                            <img src={img} height="50%" width="50%" />
                            <Typography
                                variant="h4"

                                sx = {{
                                    fontSize: {xs: "11px", sm: "16px", md: "24px", lg: "32px"}
                                }}
                            >
                                
                                {label}
                            </Typography>
                        </Grid2>
                    </CardActionArea>
                </Card>
        )
    }
}