import { Accordion, AccordionDetails, AccordionSummary, Alert, AlertTitle, Autocomplete, Backdrop, Box, Button, ButtonGroup, Card, CardContent, CardHeader, CircularProgress, Collapse, Container, Dialog, DialogActions, DialogContent, DialogContentText, DialogTitle, Divider, Drawer, FormControl, FormControlLabel, Grid2, IconButton, InputLabel, List, ListItem, ListItemButton, MenuItem, Select, Stack, Switch, TextField, Typography } from "@mui/material";
import { useEffect, useMemo, useState } from "react"
import API from "../../API/API";
import { GetRemainType } from "./Components/RemainItem";
import ClearSharpIcon from '@mui/icons-material/ClearSharp';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';



function NoDataYet(props) {

    return (
        <Box width={'100%'} height={'200px'} justifyContent='center' justifyItems='center' textAlign='center'>
            <Typography variant="h6">
                Список пуст
            </Typography>
            <Typography variant="caption" color="textSecondary">
                Начните добавлять остатки
            </Typography>
        </Box>
    );
}

function NewRemainForm({autoLoad,onClose,data,onItemAdd,loadingState,...props}) {
    
    const [loadingItemData,setLoading] = useState(false);
    const [loadedFromDB,setLoadedFromDB] = useState(false);
    const [enterByYourself,setEnterYouself] = useState(false);
    const [lock,setLock] = useState(true);
    const [hasError,setError] = useState(false);

    // VALUES
    const [lm_code,setLMCode] = useState("");
    const [remain_type,setRemainType] = useState(0);
    const [remainName,setRemainName] = useState("");
    const [sizeX,setSizeX] = useState('');
    const [sizeY,setSizeY] = useState('');
    const [useOverlock,setOverlock] = useState(false);
    const [overlockLength,setOverlockLength] = useState('');
    const [overlockPrice,setOverlockPrice] = useState('');


    const validateInputs = () => {
        return (
            (lm_code.toString().length >= 6) &&
            (sizeX*1 > 0 && sizeX*1 <= 4) &&
            (sizeY*1 > 0 && sizeY*1 <= 3) &&
            (remainName.length > 4) &&
            (!useOverlock || (overlockLength > 0 && overlockPrice > 0)) &&
            (remain_type != 0)
        )
    }

    const clearForms =() => {
        setLoadedFromDB(false);
        setLMCode('');
        setRemainType(0);
        setRemainName('');
        setSizeX('');
        setSizeY('');
        setOverlock(false);
        setOverlockLength('');
        setOverlockPrice('');
    }

    useEffect(() => {
        setLock(!validateInputs())
    },[remainName,sizeX,lm_code,sizeY,overlockPrice,overlockLength,useOverlock,remain_type]);

    useEffect(() => {
        if(!autoLoad) {clearForms(); return;}
        if(!data) return;
        loadFromData(data);
    },[autoLoad,data]);

    useEffect(() => {
        if(loadingState) clearForms();
    },[loadingState])

    const handleAddButton = (e) => {
        e.preventDefault();
        let item = {
            lm_code: lm_code,
            Name: remainName,
            item_type: remain_type,
            sizeX: sizeX,
            sizeY: sizeY,
            Overlock: (!useOverlock ? null : {meters: overlockLength, price: overlockPrice})
        }
        onItemAdd(item);
    }

    const handleSearchButton = () => {
        setLoading(true);
        (async () => {
            try {
                let data = await API.GetItemInfo(lm_code);
                loadFromData(data);
            }
            catch(e) {
                setError(true);
            }   
            finally {
                setLoading(false);
            }
        })();
    }

    const loadFromData = (data) => {
        setLMCode(data.lm_code);
        setRemainType(data.item_type);
        setRemainName(data.item_name);
        setLoadedFromDB(true);
    }

    return (
    <Box component="form" paddingTop={2} sx={{width: '100%'}}>
        <Backdrop sx={(theme) => ({ color: '#fff', zIndex: theme.zIndex.drawer + 1 })} open={loadingState || loadingItemData}><CircularProgress color="primary" /></Backdrop>
        <Stack direction="column" justifyContent="space-between" spacing={2} width={'100%'} height={'100%'}
            alignItems='center'
        >
            <Typography variant="h5" textAlign='center' flexGrow={1}>
                Добавление нового остатка
            </Typography>
            <Divider style={{width:'100%'}}/>
            <Stack direction="row" alignItems='center' spacing={1} justifyContent="center" alignContent='center' flexGrow={1}>
                <ButtonGroup>
                    <TextField type="number" id="lm_code" value={lm_code} disabled={loadedFromDB} onChange={(e) => setLMCode(e.target.value)} label="LM" size="small" sx={{width: {xs: '80%', sm: '90%', md:'500px'}}}/>
                    <Button variant="contained" disabled={loadedFromDB || loadingItemData} onClick={handleSearchButton}>Поиск</Button>
                </ButtonGroup>
                
            </Stack>
            <Collapse in={hasError}>
            <Alert severity="error">
                    Не удалось получить данные. Попробуйте ввести вручную
            </Alert>
            </Collapse>
            <FormControlLabel control={<Switch checked={enterByYourself} onChange={(e) => setEnterYouself(e.target.checked)} />} label="Ввести данные самостоятельно"/>
            <Divider style={{width:'100%'}}/>
            <Collapse in={enterByYourself || loadedFromDB} sx={{alignItems:'center'}}> {/* Базовые данные остатка */}
                <Stack direction="column" width={'90%'} spacing={2} flexGrow={1} alignItems='center' alignContent='center' justifySelf='center'>
                    <TextField fullWidth disabled={!enterByYourself} size="small" value={remainName} onChange={(e) => setRemainName(e.target.value)} label="Название остатка" />
                    <FormControl fullWidth>
                        <InputLabel id="remain-type-label">Тип остатка</InputLabel>
                        <Select
                            size="small"
                            labelId="remain-type-label"
                            id="remain-type-control"
                            value={remain_type}
                            label="Age"
                            onChange={(e) => setRemainType(e.target.value)}
                            disabled={!enterByYourself}
                        >
                            <MenuItem value={0}>Не выбрано</MenuItem>
                            <MenuItem value={1}>Линолеум</MenuItem>
                            <MenuItem value={2}>Ковролин</MenuItem>
                            <MenuItem value={3}>Ковровая дорожка</MenuItem>
                            <MenuItem value={4}>Резиновое покрытие</MenuItem>
                            <MenuItem value={5}>Травяное покрытие</MenuItem>
                        </Select>
                    </FormControl>
                    <Stack direction='row' flexGrow={1} justifyContent='space-between' spacing={1}>
                        <TextField size="small" type="number" value={sizeX} onChange={(e) => setSizeX(e.target.value)} label="Ширина" />
                        <TextField size="small" type="number" value={sizeY} onChange={(e) => setSizeY(e.target.value)} label="Длина" />
                    </Stack>
                    
                    <Collapse in={remain_type == 2 || remain_type == 3 || remain_type == 5}> {/* ОВЕРЛОК */}
                        <Stack direction="column" pacing={2} flexGrow={1} alignItems='center' alignContent='center' justifySelf='center'>
                            <FormControlLabel control={<Switch checked={useOverlock} onChange={(e) => setOverlock(e.target.checked)} />} label="Добавить оверлок"/>
                        </Stack>
                        <Stack direction='row' flexGrow={1} justifyContent='space-between' spacing={1}>
                            <TextField size="small" type="number" disabled={!useOverlock} value={overlockLength} onChange={(e) => setOverlockLength(e.target.value)} label="Длина оверлока" />
                            <TextField size="small" type="number" disabled={!useOverlock} value={overlockPrice} onChange={(e) => setOverlockPrice(e.target.value)} label="Цена за п.м." />
                        </Stack>
                    </Collapse>


                    <Button fullWidth type="submit" disabled={lock} onClick={handleAddButton} variant="contained">Добавить</Button>
                    
                </Stack>

                
            </Collapse>
            <Button fullWidth  onClick={() => onClose()}>Отмена</Button>
        </Stack>
    </Box>
    )
}

function FastEnterInputField({onItemSelected,...props}) {

    const [open,setOpen] = useState(false);
    const [loading,setLoading] = useState(false);
    const [items,setItems] = useState([]);

    const handleOpen = () => {
        setOpen(true);
        setLoading(true);
        (async () => {
            try {
            let result = await API.GetItemNames();
            setItems(result.items);
            }
            catch(e) {

            }
            finally {
                setLoading(false);
            }
        })();
    }

    const handleClose = () => {
        setOpen(false);
        setLoading(false);
        setItems([]);
    }

    const handleSelect = (event,value) => {
        onItemSelected(value.lm_code);
        event.target.firstChild.data = "";
    }

    return (
        <Autocomplete
            id="fast-add-bar"
            open={open}
            onOpen={handleOpen}
            onClose={handleClose}
            loading={loading}
            getOptionLabel={(options) => options.Name}
            noOptionsText="Не найдено. Добавьте вручную"
            loadingText="Загрузка..."
            disableClearable={true}
            
            onChange={handleSelect}
            options={items}
            renderInput={(params) => <TextField {...params} type="search" label="Быстрое добавление остатка" size="small" fullWidth/>}
        />
    )
}


function AddRemainElement({item,index,onRemove,...props}) {

    useEffect(() => {},[item,index])

    return (
        <ListItemButton divider sx={{backgroundColor: '#fcfcfc', padding: 1}}>
            <Box width='100%'>
            <Stack direction='row' justifyContent={'space-between'} alignItems='flex-start' paddingRight={1}>
                    <Typography
                        paddingLeft={2}
                        variant='h6'
                    >
                        {item.Name}
                    </Typography>
                    <IconButton  onClick={() => onRemove(index)} size='small' >
                        <ClearSharpIcon fontSize='small'  />
                    </IconButton>
            </Stack>
            <Stack direction='column' flexGrow={1} padding={2} paddingTop={0} >
                
                <Stack direction='row' justifyContent='space-between' alignItems='end' flexGrow={1}>
                    
                </Stack>
                <Divider />
                <Stack direction='row' justifyContent='space-between' alignItems='end' flexGrow={1}>
                    <Typography
                        variant='caption'
                    >
                        {GetRemainType(item.item_type)}
                    </Typography>
                    <Typography
                        variant='caption'
                    >
                        LM: {item.lm_code}
                    </Typography>
                </Stack>
                <Typography variant="body1">
                    Размеры
                </Typography>
                <Grid2 container columns={12} paddingTop={1} spacing={2}>
                    <Grid2 size={{xs: 6, sm: 6, md: 6, lg: 6}}>
                        <Card variant='outlined' sx={{backgroundColor: '#f9f9f9', minHeight: '115px'}}>
                            <Stack direction='column' padding={1} spacing={1}>
                                <Typography
                                    variant="body1"
                                    align="center"
                                >
                                    <b>РАЗМЕРЫ</b>
                                </Typography>
                                <Divider sx={{width: '100%'}}/>
                                <Typography
                                    variant="body1"
                                >
                                    Ширина: {(item.sizeX*1).toFixed(2)} м
                                </Typography>
                                <Typography
                                    variant="body1"
                                >
                                    Длина: {(item.sizeY*1).toFixed(2)} м
                                </Typography>
                            </Stack>
                        </Card>
                    </Grid2>
                    <Grid2 size={{xs: 6, sm: 6, md: 6, lg: 6}} >
                        <Card variant='outlined' sx={{backgroundColor: '#f9f9f9', minHeight: '115px'}}>
                            <Stack direction='column' padding={1} spacing={1}>
                                <Typography
                                    variant="body1"
                                    align="center"
                                >
                                    <b>ОВЕРЛОК</b>
                                </Typography>
                                <Divider sx={{width: '100%'}}/>
                                { item.Overlock ? <>
                                <Typography
                                    variant="body1"
                                >
                                    Длина: {(item.Overlock.meters*1).toFixed(2)} п.м.
                                </Typography>
                                <Typography
                                    variant="body1"
                                >
                                    Цена: {(item.Overlock.price*1).toFixed(2)} р/п.м.
                                </Typography>
                                </> : <>
                                <Typography
                                    variant="body1"
                                    align="center"
                                >
                                    НЕТ
                                </Typography>
                                </>}
                            </Stack>
                        </Card>
                    </Grid2>
                </Grid2>
            </Stack>
            </Box>
        </ListItemButton>
    )
}

function FailedRemain({remainData,...props}) {
    
    const [loading,setLoading] = useState(false);
    const [resolved,setResolved] = useState(false);
    const [error,setError] = useState({error: false})

    const handleAddRemain = (e) => {
        setLoading(true);
        (async () => {
            try {
                let result = await API.AddNewItem(remainData);
                setResolved(true);
            }
            catch(e) {
                setError({error: true})
            }
            finally {
                setLoading(false);
            }
        })();
    }

    return (
        <Card variant="outlined">
                                    <CardContent>
                                    <Stack direction='column' spacing={1}>
                                        <Typography variant="h6">{remainData.Name}</Typography>
                                        <Divider />
                                        <Alert
                                            severity="warning"
                                        >
                                            Данный остаток не был добавлен, так как не находится в базе данных
                                        </Alert>
                                        <Typography>
                                            Решения:
                                        </Typography>
                                        {!error.error ?
                                        <Button fullWidth disabled={loading || resolved} onClick={() => handleAddRemain()} variant="contained" color={!resolved ? "primary" : "success"}>
                                            {resolved ? "Добавлено в базу данных" : <>
                                                {!loading ? "Добавить в базу данных" : <CircularProgress size='14px' />}
                                            </>
                                            }
                                        </Button>
                                        :
                                        <Alert severity="error">
                                            Не удалось добавить остаток в базу данных. Попробуйте позже.
                                        </Alert>
                                        }
                                    </Stack>
                                    </CardContent>
                                </Card>
    )
}

function ResultDialog({data,show,onClose,...props}) {

    return (
        <Dialog
            open={show}
            fullScreen
            scroll='body'
        >
            <DialogTitle>Результат</DialogTitle>
            <Divider />
            <DialogContent>
                <DialogContentText>
                    <Stack container direction='column' spacing={1}>
                        <Alert
                            severity={data?.failed > 0 ? "error" : "success"}
                        >
                            <AlertTitle>
                                {data?.failed > 0 ? "При добавлении произошла ошибка" : 'Новые остатки успешно зарегистрированы'}
                            </AlertTitle>
                            {data?.failed > 0 ? <>Некоторые остатки не были добавлены.<br/><br/>
                            Проверьте "Ошибки" и выполните действия, после чего повторите.</> : 'Новые остатки успешно зарегистрированы'}
                        </Alert>
                        <Stack direction='row' flexGrow={1} justifyContent='space-between'>
                            <b>Добавлено:</b>
                            {data?.added}
                        </Stack>
                        <Stack direction='row' flexGrow={1} justifyContent='space-between'>
                            <b>Не добавлено:</b>
                            {data?.failed}
                        </Stack>

                        {data?.failed > 0 && <>
                        <Accordion>
                            <AccordionSummary expandIcon={<ExpandMoreIcon />}>
                                Ошибки
                            </AccordionSummary>
                            <AccordionDetails  sx={{backgroundColor: '#f9f9f9'}}>
                                <Stack direction='column' spacing={1} flexGrow={1}>
                                {data?.failedItems.map((item,index) => <FailedRemain remainData={item} />)}
                                </Stack>
                            </AccordionDetails>
                        </Accordion>
                    </>}
                    </Stack>
                </DialogContentText>
                <DialogActions>
                    <Button onClick={onClose}>Продолжить</Button>
                </DialogActions>
            </DialogContent>
        </Dialog>
    )
}

export default function CreateRemainsPage(props) {
    
    const [remainList,setRemainList] = useState([]);
    const [drawerOpen,setDrawerOpen] = useState(false);
    const [loadingState,setLoading] = useState(false);

    const [dataToDrawer,setDataDrawer] = useState(null);
    const [autoLoad,setAutoLoad] = useState(false);
    const [resultData,setResult] = useState(null);
    const [openResult,setOpenResult] = useState(false);

    const onItemAdd = (item) => {
        setDrawerOpen(false);
        remainList.push(item);
    }

    const onItemRemove = (index) => {
        var newRemainList = [...remainList];
        newRemainList.splice(index,1);
        setRemainList(newRemainList);
    }

    const onHandleSearchElement = (lm_code) => {
        setLoading(true);
        setDrawerOpen(true);
        
        setAutoLoad(true);
        (async () => {
            setTimeout(async () => {
                let data = await API.GetItemInfo(lm_code);
                setDataDrawer(data);
                setAutoLoad(true);
                setLoading(false);
            },500)
        })();
    }

    const handleNewButton = () => {
        setAutoLoad(false);
        setDataDrawer(null);
        setDrawerOpen(true);
    }

    const finishRemainsHandle = () => {
        setLoading(true);
        (async () => {
            try {
                var data = await API.PostNewRemains(remainList);
                setRemainList([...data.failedItems]);
                setResult(data);
                setOpenResult(true);
            }
            catch(e) {
                console.log(e);
            }
            finally {
                setLoading(false);
            }
        })();
    }

    return (<>
        <ResultDialog show={openResult} data={resultData} onClose={() => setOpenResult(false)} />
        <Grid2 id="test" container columns={14} justifyContent='center' sx={{minHeight:'100%'}} paddingTop={{xs: 0, sm: 0, md: 2, lg: 2}} spacing={1}>
            <Grid2 size={{xs: 14, sm: 14, md: 7, lg: 7}} sx={{minHeight:'100%'}}>
                <Stack direction="column" spacing={1} >
                    <Card variant="outlined">
                        <Stack direction="column" padding={2} spacing={1}>
                            <Typography variant="h4" component='p'>
                                Создание остатков
                            </Typography>
                            <Box>  
                                <FastEnterInputField onItemSelected={onHandleSearchElement}/>
                            </Box>
                            <Button fullWidth variant='contained' size='small' onClick={handleNewButton}>Добавить новый</Button>
                            <Button fullWidth disabled={remainList.length == 0} variant='outlined' color="success" size='small' onClick={() => finishRemainsHandle()}>Завершить</Button>
                        </Stack>
                    </Card>
                    {/* ЗОНА НОВЫХ ОСТАТКОВ*/}
                    <Card variant="" sx={{minHeight:'100%'}}>
                        <Stack direction="column" paddingTop={1} spacing={0}>
                            <Typography variant="h4" component='p' textAlign='center'>
                                Список новых остатков
                            </Typography>
                            <Divider />
                            <Stack direction='column' spacing={1} sx={{ width:'100%'}} >  
                                <List sx={{paddingTop: 0}}>
                                {remainList.length == 0 ? <NoDataYet /> :
                                    remainList.map((item,index) => <AddRemainElement key={index} item={item} index={index} onRemove={onItemRemove} />)
                                }
                                </List>
                            </Stack>
                        </Stack>
                    </Card>
                </Stack>
            </Grid2>
            
        </Grid2>
        <Drawer
            id="SS"
            open={drawerOpen}
            onClose={() => setDrawerOpen(false)}
            anchor="bottom"
            PaperProps={{
                sx: {
                    minHeight: {
                        xs: '90vh',
                        sm: '90vh',
                        md: '80vh',
                        lg: '80vh'
                    }
                }
            }}
        >
                <NewRemainForm onItemAdd={onItemAdd} autoLoad={autoLoad} data={dataToDrawer} onClose={() => setDrawerOpen(false)} loadingState={loadingState}/>
        </Drawer></>
    );
}