import logo from './logo.svg';
import './App.css';
import Button from '@mui/material/Button';
import * as React from 'react';
import { Container } from '@mui/material';
import { Route, Routes, useNavigate } from 'react-router-dom';
import axios from 'axios';
import Cookies from 'universal-cookie';
import MainMenuPage from './Pages/MainMenu/MainMenuPage';
import MenuBar from './GlobalComponents/MenuBar';
import ServiceDisabled from './Pages/ServiceDisabled';
import RemainMenuPage from './Pages/MainMenu/RemainsMenu/RemainsMenuPage';
import RemainsListPage from './Pages/Remains/RemainsListPage';
import AuthPage from './Pages/AuthPage';
import API from './API/API';
import axiosRetry from 'axios-retry';
import CreateRemainsPage from './Pages/Remains/CreateRemainsPage';
import { PrintPage } from './Pages/Remains/PrintPage';
import { ChartsPage } from './Pages/Remains/Charts';

const cookies = new Cookies();
export const UserContext = React.createContext({
  Name: '',
  setName: () => {}
});


axios.interceptors.request.use((request) => {
  let accessToken = cookies.get('access-token');
  if(!accessToken) return request;
  request.headers['Authorization'] = `Bearer ${accessToken}`;
  return request;
});

export async function refreshCookies() {
  try {
  let cookies = new Cookies();
  let refresh = cookies.get("refresh-token");
  if(!refresh) return false;
  let data = await API.RefreshTokens(refresh);
  cookies.remove('refresh-token');
  cookies.remove('access-token');
  cookies.set('refresh-token',data.tokens.refresh);
  cookies.set('access-token',data.tokens.access);
  return true;
  }
  catch(e) {
    return false;
  }
}

axios.interceptors.response.use(response => response,
  async (error) => {
    if(error.status == 403) {
      try {
          let cookies = new Cookies();
          let refresh = cookies.get("refresh-token");
          if(!refresh) return error;
          let data = await API.RefreshTokens(refresh);
          cookies.remove('refresh-token');
          cookies.remove('access-token');
          cookies.set('refresh-token',data.tokens.refresh);
          cookies.set('access-token',data.tokens.access);
          return axios.request(error.config);
        }
        catch(e) {
          return error;
        }
    }
    if(error.status == 401 && window.location.pathname != "/auth") {
      window.location.href = "/auth";
      return error;
    }
    return error;
  }
)

function App() {

  const [User,setUser] = React.useState(null);

  const navigator = useNavigate();

  React.useEffect(() => {
      API.RequestManifest(() => {
          navigator("/auth");
      });
      API.CheckAuth(username => {
        setUser(username);
      })
  },[]);

  return (
      <UserContext.Provider value={{User,setUser}}>
        <MenuBar />
        <Routes>
          <Route path="/" element={<MainMenuPage />}/>
          <Route path="/auth" element={<AuthPage />}/>
          <Route path="/remains" element={<RemainMenuPage />} />
          <Route path="/remains/list" element={<RemainsListPage />} />
          <Route path="/remains/create" element={<CreateRemainsPage />} />
          <Route path="/remains/print" element={<PrintPage />} />
          <Route path="/remains/overview" element={<ChartsPage />} />
          <Route path="/mixes" element={<ServiceDisabled />} />
          <Route path="/orders" element={<ServiceDisabled />} />
          <Route path="/nightTasks" element={<ServiceDisabled />} />
        </Routes>
      </UserContext.Provider>
  );
}

export default App;
