import { Alert, AlertTitle, AppBar, Box, Button, Card, CardActionArea, CircularProgress, Container, Divider, Drawer, Grid2, Paper, Stack, TextField, Typography } from "@mui/material";
import { useEffect, useRef, useState } from "react";
import RemainFullInfo from "./Components/RemainsFullInfo";
import API from "../../API/API";
import RemainItem from "./Components/RemainItem";
import RemainList from "./Components/RemainList";


const testRemainData = {
    lm_code: "12345678",
    name: "Линолеум Венский 3м",
    type: "Линолеум",
    sizeX: 3,
    sizeY: 1,
    createdBy: "Евгений А.",
    selled: false,
    createdDate: new Date("10-20-2024"),
    confirmedDate: new Date("10-25-2024"),
    overlock: null,
    printed: true,

}

var delayedSearchTimeout;

export default function RemainsListPage(props) {

    const [showDrawer,setDrawer] = useState(false);
    const [remainItem,setRemain] = useState(null);
    const [loadingNextData,setLoadingData] = useState(false);

    const [filterText,setFilterText] = useState("");



    async function FetchData(targetPage) {
        
        let data = await API.GetRemainList(targetPage);
        let newData = [...data.data.data];
        let result = newData.concat(data.data.data);
        setTimeout(() => {
            setLoadingData(false);
        },3000);
    }

    

    

    const handleClose = () => {
        setDrawer(false);
    }

    const loadRemainData = (item) => {
        setRemain(item);
        setDrawer(true);
    }

    const handleItemRemove = (id) => {
        let item = {...remainItem};
        item.List = item.List.filter(d => d.id != id);
        setRemain(item);
    }

    const handleSearchChange = (e) => {
        clearTimeout(delayedSearchTimeout);
        delayedSearchTimeout = setTimeout(() => {
            setFilterText(e.target.value);
        },700);
    }

    return (
        <>
                <Grid2 container 
                    padding={0}
                    columns={12}
                    spacing={0}
                >
                    <Grid2 size={12}>
                        <Alert severity="warning">
                            <AlertTitle>Экспериментальный режим</AlertTitle>
                            Данный сервис работает в экспериментальном режиме. Могут быть ошибки в работе.
                        </Alert>
                    </Grid2>
                    <Drawer
                        anchor="right"
                        variant="persistent"
                        PaperProps={{
                            sx: {width: '100%'}
                        }}
                        open={showDrawer}
                        transitionDuration={400}
                        sx={{
                            display: { md: 'none', lg:'none'}
                        }}
                        
                    >
                        <Container>
                            <Grid2 container direction="column">
                                <Button onClick={() => {setDrawer(false)}} sx={{padding: 2}}>Закрыть</Button>
                                <RemainFullInfo remainData={remainItem} onItemRemove={handleItemRemove}/>
                            </Grid2>
                        </Container>
                    </Drawer>

                    <Grid2 size={{xs: 12, sm: 12, md: 4.5, lg: 4.5}} paddingTop={1}>
                        <AppBar position="sticky" color="background" elevation={0}>
                            <Box padding={1}>
                                <TextField width="90%" onChange={handleSearchChange} fullWidth size="small" label="Поиск остатка"/>
                            </Box>
                        </AppBar>
                        
                        <RemainList onItemClick={loadRemainData} filterText={filterText}/>
                    </Grid2>
                    <Grid2 size={{ md: 7.5, lg: 7.5}} display={{sm: 'none', xs: 'none', md: 'flex', lg: 'flex'}} paddingTop={1}>
                            <Container sx={{}}>
                                <Paper variant="outlined" sx={{padding: 2, minHeight:'75vh'}}>
                                    <RemainFullInfo  remainData={remainItem} onItemRemove={handleItemRemove}/>
                                </Paper>
                            </Container>
                    </Grid2>
                </Grid2>
        </>
    );
}