import { Box, Card, CardContent, CircularProgress, Typography } from "@mui/material";
import { BarChart, PieChart } from "@mui/x-charts";
import { useEffect } from "react"

const monthNames = [
    "Январь",
    "Февраль",
    "Март",
    "Апрель",
    "Май",
    "Июнь",
    "Июль",
    "Август",
    "Сентябрь",
    "Октябрь",
    "Ноябрь",
    "Декабрь",
];

export function RemainsLifeTime({data,...props}) {
    
    useEffect(() => {
    },[data]);

    return (
        <Card variant="outlined">
                        <CardContent>
        <Typography variant="h5">
            Среднее время жизни
        </Typography>
        <Typography variant="h6">
            В днях
        </Typography>
        {data == null ? <Box sx={{minHeight: "300px"}} display="flex-column" justifyItems="center" alignContent="center">
            <CircularProgress />
            <Typography variant="h6">
                Загружаю данные...
            </Typography>
        </Box>
        :
        <BarChart 
            xAxis={[{scaleType: 'band', data: data.map(d => d.Size)}]}
            series={[
                {data: data.map(d => d.LifeTime)}
            ]}
            height={300}
            barLabel="value"
        />}
        </CardContent>
        </Card>
    )
}