import { Button, ListItem, Stack, TextField, Typography } from "@mui/material";
import { useState } from "react";



export function UnprintedElement({element,onItemPriceChange,...props}) {

    const [price,setPrice] = useState('');

    const handlePrice = (e) => {
        setPrice(e.target.value);
        element.price = e.target.value;
        onItemPriceChange && onItemPriceChange(element,e.target.value);
    }

    return (
        <ListItem divider>
                    <Stack direction='column' flexGrow={1}>
                        <Typography variant="h5">
                            {element.Name}
                        </Typography>
                        <Typography variant="body2">
                            Новых остатков: {element.List.length}
                        </Typography>
                        <Stack flexGrow={1} direction='row' alignItems='center' justifyContent='space-between' paddingTop={1} spacing={3}>
                            <Stack direction='row' alignItems='center' spacing={3}>
                            <Typography variant="body1">
                                Цена:
                            </Typography>
                            <TextField type="number" value={price} onChange={handlePrice} size="small"/>
                            </Stack>
                            <Button variant="outlined"  color="info" onClick={() => {
                        var w = window.open(`https://ekaterinburg.lemanapro.ru/search/?q=${element.lm_code}`).focus();
                        }}>Проверить цену на сайте</Button>
                        </Stack>
                    </Stack>
        </ListItem>
    )
}