import { Box, Card, CardContent, CircularProgress, Typography } from "@mui/material";
import { BarChart, PieChart } from "@mui/x-charts";
import { useEffect } from "react"

const monthNames = [
    "Январь",
    "Февраль",
    "Март",
    "Апрель",
    "Май",
    "Июнь",
    "Июль",
    "Август",
    "Сентябрь",
    "Октябрь",
    "Ноябрь",
    "Декабрь",
];

export function RemainsTotalSizeChart({data,...props}) {
    
    useEffect(() => {
    },[data]);

    return (
        <Card variant="outlined">
                        <CardContent>
        <Typography variant="h5">
            Распределение остатков по ширинам
        </Typography>
        <Typography variant="h6">
            За все время
        </Typography>
        {data == null ? <Box sx={{minHeight: "300px"}} display="flex-column" justifyItems="center" alignContent="center">
            <CircularProgress />
            <Typography variant="h6">
                Загружаю данные...
            </Typography>
        </Box>
        :
        <PieChart 
            series={[
                {
                    data: data.map(d => {
                        let res = {
                            arcLabel: (item) => `${item.Total}`,
                            value: d.Total,
                            label: `${d.Size}`
                        }
                        return res;
                    })
                }
            ]}
            height={300}
        />}
        </CardContent>
        </Card>
    )
}