import { AppBar, Avatar, Box, Button, Container, IconButton, Stack, Toolbar, Typography } from "@mui/material";
import { Fragment, useContext } from "react";
import { UserContext } from "../App";
import { yellow } from "@mui/material/colors";
import { useLocation, useNavigate } from "react-router-dom";
import ArrowBackOutlinedIcon from '@mui/icons-material/ArrowBackOutlined';



function getLetters(name) {
    let words = name.split(' ');
    let result = ''
    for(let word of words) {
        result += word[0];
    }
    return result.toUpperCase();
}

function BackButton() {
    const history = useNavigate();

    return (
        <IconButton aria-label="Назад" onClick={() => history(-1)}>
            <ArrowBackOutlinedIcon />
        </IconButton>
    )
}

export default function MenuBar({...props}) {

    const location = useLocation();    
    const { User } = useContext(UserContext);

    return (
        <Fragment>
            <AppBar position="fixed">
                
            <Container fixed>
                <Toolbar>
                        {
                            location.pathname != "/" && location.pathname != "/auth" && <BackButton />
                        }
                        <Typography
                            sx={{flexGrow: 1}}
                            variant="h5"
                        >
                            Помощник 05-25
                        </Typography>
                        {User != null && (
                        <>
                        <Box>
                            <Avatar 
                                src="/static/images/avatar/1.jpg"
                                sx={{ bgcolor: yellow[800] }}
                            >{getLetters(User.Name)}</Avatar>
                        </Box>
                        </>)}
                </Toolbar>
                
                </Container>
            </AppBar>
            <Toolbar />
        </Fragment>
    );
}