import { Badge, Card, CardActionArea, Chip, Divider, Grid2, Paper, Stack, Typography } from "@mui/material"
import PrintDisabledOutlinedIcon from '@mui/icons-material/PrintDisabledOutlined';
import FiberNewOutlinedIcon from '@mui/icons-material/FiberNewOutlined';
import DangerousOutlinedIcon from '@mui/icons-material/DangerousOutlined';

export function GetRemainType(type_id) {
    switch(type_id) {
        case 1: return "Линолеум"
        case 2: return "Ковролин"
        case 3: return "Ковровая дорожка"
        case 4: return "Резиновое покрытие"
        case 5: return "Травяное покрытие"
        default: return "Неизвестно"
    }
}

export function CalculateDays(targetDate) {
    let Now = new Date();
    let Target = new Date(targetDate);
    const oneDay = 1000 * 60 * 60 * 24;
    const diffInTime = Now.getTime() - Target.getTime();
    const diffInDays = Math.round(diffInTime / oneDay);
    return diffInDays;
}

export function OldCount(item) {

    var count = 0;
    for(var remain of item.List) {
        if(CalculateDays(remain.ConfirmedDate) > 7) {
            count += 1;
        }
    }


    return (count > 0 && 
      <Badge badgeContent={count} color="error">
        <DangerousOutlinedIcon color="action" />
      </Badge>)
}

export function Count(item) {


    return (<Chip label={`Остатков: ${item.List.length}`} variant="outlined" />)
}

export function NewCount(item) {

    var count = 0;
    for(var remain of item.List) {
        if(CalculateDays(remain.AddedDate) <= 2) {
            count += 1;
        }
    }


    return (count > 0 && 
      <Badge badgeContent={count} color="success">
        <FiberNewOutlinedIcon color="action" />
      </Badge>)
}

export function CalculateS(item) {

    var S = 0;
    for(var remain of item.List) {
        S += remain.sizeX*remain.sizeY
    }


    return (<Chip label={`Общая площадь: ${S.toFixed(2)} м2`} variant="outlined" />)
}

export function IsPrinted(item) {

    var count = 0;
    for(var remain of item.List) {
        if(!remain.Printed) {
            count += 1;
        }
    }


    return (count > 0 && 
      <Badge badgeContent={count} color="warning">
        <PrintDisabledOutlinedIcon color="action" />
      </Badge>)
}

export default function RemainItem({item,onClick,...props}) {

    return (
        
                                <Stack direction='column'>
                                    <Card variant="outlined">
                                        <CardActionArea onClick={() => {onClick(item)}}>
                                            <Grid2 container columns={6} padding={1}>
                                                <Grid2 size={6}>
                                                    <Typography
                                                        variant="h6"
                                                    >
                                                        {item.Name}
                                                    </Typography>
                                                    <Divider />
                                                    <Stack direction="row" justifyContent="space-between" padding={0.5}>
                                                        <span>LM: {item.lm_code}</span>
                                                        <span>{GetRemainType(item.item_type)}</span>
                                                    </Stack>
                                                    <Grid2 container paddingTop={2} direction="column" justifyItems='center' spacing={1}>
                                                            {Count(item)}
                                                            {CalculateS(item)}
                                                            <Stack direction="row" spacing={2} padding={1}>
                                                                {IsPrinted(item)}
                                                                {NewCount(item)}
                                                                {OldCount(item)}
                                                            </Stack>
                                                    </Grid2>
                                                </Grid2>
                                            </Grid2>
                                        </CardActionArea>
                                    </Card>
                </Stack>
        
    )
}