import { Alert, AlertTitle, Box, Button, Card, CircularProgress, Collapse, Dialog, DialogActions, DialogContent, DialogContentText, DialogTitle, Divider, Grid2, Link, Paper, Slide, Snackbar, Stack, Step, StepLabel, Stepper, TextField, Typography } from "@mui/material";
import { forwardRef, useContext, useEffect, useState } from "react";
import InputMask from "react-input-mask";
import API from "../API/API";
import { UserContext } from "../App";
import Cookies from "universal-cookie";
import { useNavigate } from "react-router-dom";



function parsePhone(value) {
    const parsedValue = value.replace(/\D/gm,'')
    return parsedValue;
}

function GrantAccessComponent({OnCancel,OnFinished,...props}) {

    const [step,setStep] = useState(0);
    const [phone,setPhone] = useState("");
    const [loading,setLoading] = useState("");

    const [phoneIsValid,setPhoneValid] = useState(false);

    const [resetData,setResetData] = useState(null);
    const [errorData,setErrorData] = useState({error: false, message: ""})

    const [password,setPassword] = useState('');
    const [repeatPassword,setRPassword] = useState('');
    const [passwordErrorData,setPasswordErrorData] = useState({error: false, message: ""})

    const steps = [
        "Прочти информацию",
        "Введи номер телефона",
        "Установи пароль"
    ];

    useEffect(() => {
        var parsedPhone = parsePhone(phone);
        setPhoneValid(parsedPhone.length === 11);
    },[phone])

    const handleDisable = () => {
        if(loading) return true;
        switch(step) {
            case 0: { return false; }
            case 1: { return !phoneIsValid;}
            case 2: { return false; }
            case 3: { return false; }
            default: return true;
        }
    }

    const nextStepHandle = () => {
        switch(step) {
            case 0: { setStep(step+1); break;}
            case 1: { handlePhoneStep(); break;}
            case 2: { handlePasswordStep(); break;} //Finish
        }
    }

    const handlePhoneStep = () => {
        setErrorData({error: false,message:''});
        setLoading(true);
        (async () => {
            try {
                let result = await API.RequestPasswordReset(parsePhone(phone));
                setResetData(result);
                console.log(result);
                setStep(step+1);
            }
            catch(e) {
                if(e === "ALREADY_RESETED") {
                    setErrorData({error: true, message:"Вы уже получали доступ."})
                }
                else {
                    setErrorData({error: true, message:"Телефона нет в списке разрешенных"})
                }
            }
            finally {
                setLoading(false);
            }
        })();
    }

    const handlePasswordStep = () => {
        setPasswordErrorData({error: false,message:''});
        setLoading(true);
        if(password != repeatPassword) {
            setPasswordErrorData({error: true, message: 'Пароли не совпадают'});
            setLoading(false);
            return;
        }
        (async () => {
            try {
                let result = await API.ResetPassword(resetData.ResetCode,password);
                console.log(result);
                if(result == "OK") {
                    OnFinished();
                }
                else {
                    console.log(result);
                    setPasswordErrorData({error: true, message: 'Произошла ошибка при установке пароля. Попробуйте заново'});
                }
            }
            catch(e) {
                setPasswordErrorData({error: true, message: 'Произошла ошибка при установке пароля. Попробуйте заново'});
            }
            finally {
                setLoading(false);
            }
        })();
    }

    const backStepHandle = () => {
        if(step == 0) {
            OnCancel();
            return;
        }
        setStep(step-1);
    }


    return (
        <Stack container direction="column" spacing={2}>
            <Stepper activeStep={step} alternativeLabel>
                {steps.map(label => (
                    <Step key="label">
                        <StepLabel>{label}</StepLabel>
                    </Step>
                ))}
            </Stepper>
            <Divider />
            {step === 0 && (
                <>
                    <Typography
                        variant="h4"
                    >
                        Инфомация
                    </Typography>
                    <Typography variant="body1">
                        Данное веб-приложение предназначено для выполнения рутинных операций в отделе "Напольные покрытия"<br/><br/>
                        Для доступа к приложению необходимо указать свой номер телефона и установить пароль. Требования к паролю следующие:
                        <ul>
                            <li>Не используй пароль от копоративных ресурсов. Данный сервис не являтеся официальным.</li>
                        </ul>
                    </Typography>
                </>
            )}
            {step === 1 && (
                <>
                    <Typography
                        variant="h4"
                    >
                        Номер телефона
                    </Typography>
                    <Typography variant="body1">
                        Введи свой номер телефона.<br/><br/>Если ты работаешь в отделе напольных покрытий - твой телефон уже зарегистрирован.
                    </Typography>
                    <InputMask
                        mask="+7(999)999-99-99"
                        value={phone}
                        disabled={loading}
                        maskChar="_"
                        onChange={(e) => setPhone(e.target.value)} 
                    >
                    {() => <TextField id="phone"  type="phone" label="Телефон" variant="outlined" placeholder="+7(999)999-99-99" />}
                    </InputMask>
                    <Collapse in={errorData.error}>
                        <Alert severity="error">
                            {errorData.message}
                        </Alert>
                    </Collapse>
                </>
            )}
            {step === 2 && (
                <>
                    <Typography
                        variant="h4"
                    >
                        Установи пароль
                    </Typography>
                    <Typography variant="caption">
                        Пароли хранятся зашифрованными.<br/> Однако, я бы рекомендовал не использовать пароли от корпоративных сервисов.
                    </Typography>
                    <TextField id="password" value={password} onChange={(e) => setPassword(e.target.value)}  type="password" label="Пароль" variant="outlined" />
                    <TextField id="password2" value={repeatPassword} onChange={(e) => setRPassword(e.target.value)}  type="password" label="Повтори пароль" variant="outlined" />
                    <Collapse in={passwordErrorData.error}>
                        <Alert severity="error">
                            {passwordErrorData.message}
                        </Alert>
                    </Collapse>
                </>
            )}
            <Stack direction='row' container flexGrow={1} justifyContent="space-between">
                        <Button color="inherit" onClick={() => backStepHandle()}>Назад</Button>
                        <Button color="primary" variant="contained" disabled={handleDisable()} onClick={nextStepHandle}>
                            {loading ? <CircularProgress size='16px' color="inherit"/> :
                            (   <>
                                {step === steps.length-1 ? "Завершить" : "Далее"}
                                </>
                            )}
                        </Button>
            </Stack>
        </Stack>
    )
}


const cookies = new Cookies;
const Transition = forwardRef(function Transition(props, ref) {
    return <Slide direction="up" ref={ref} {...props} />;
  });

export default function AuthPage(props) {

    const navigator = useNavigate();

    const { setUser } = useContext(UserContext);


    const [phone,setPhone] = useState("");
    const [password,setPassword] = useState("");
    const [loading,setLoading] = useState(false);

    const [hasError,setError] = useState(false);
    const [errorText, setErrorText] = useState("");

    const [grantAccess,setGrantAccess] = useState(false);

    const [finishedAccess,setFinishedAccess] = useState(false);
    const [showDialog,setDialog] = useState(false);

    const onLoginPressed = (e) => {
        e.preventDefault();
        setLoading(true);
        setError(false);
        setTimeout(async () => {
            try {
            let result = await API.Auth(parsePhone(phone),password);
            
            setUser(result.user);
            cookies.set('access-token',result.tokens.access);
            cookies.set('refresh-token',result.tokens.refresh);
            navigator("/");
            setLoading(false);
            }
            catch(e) {
                console.log(e);
                if(e === 404) {
                    setError(true);
                    setErrorText("Введен неверный телефон или пароль")
                }
                if(e === 500) {
                    setError(true);
                    setErrorText("Произошла внутренняя ошибка. Попробуйте позже")
                }
            }
            finally {
                setLoading(false);
            }
        },1000);
    }

    

    return (
        <Grid2 container
            sx={{height: '75vh'}}
            justifyContent='center'
            alignContent='center'
            direction='column'
        >
            
                <Paper sx={{padding: 2, minWidth: {xs: '300px', sm:'300px', md:'400px',lg:'400px'}, maxWidth: {xs: '350px', sm:'350px', md:'450px',lg:'450px'}}}>
                {!grantAccess ? 
                <Stack component='form' direction="column" spacing={2}>
                    <Typography
                        variant="h4"
                        component="p"
                        textAlign="center"
                    >
                        Авторизация
                    </Typography>
                    <InputMask
                        mask="+7(999)999-99-99"
                        value={phone}
                        disabled={loading}
                        maskChar="_"
                        onChange={(e) => setPhone(e.target.value)} 
                    >
                    {() => <TextField id="phone"  type="phone" label="Телефон" variant="outlined" placeholder="+7(999)999-99-99" />}
                    </InputMask>
                    
                    <TextField id="password" disabled={loading} type="password" onChange={(e) => setPassword(e.target.value)} value={password} label="Пароль" variant="outlined" />
                    <Collapse in={hasError}>
                        <Alert severity="error">
                            {errorText}
                        </Alert>
                    </Collapse>
                    <Button variant="contained" type="submit" disabled={loading} onClick={onLoginPressed}>
                        {!loading ? "ВХОД" : <CircularProgress size='24px' /> }
                    </Button>
                    <Divider />
                    <Typography variant="caption" textAlign='center'>
                        Еще не устанавливал пароль?
                    </Typography>
                    <Button onClick={() => setGrantAccess(true)}>Получить доступ</Button>
                    <Typography variant="caption" textAlign='center' sx={{paddingTop: 2}}>
                        <Link href="#whyAuth" underline='none' color='secondary' onClick={() => setDialog(true)}>Зачем нужна авторизация?</Link>
                    </Typography>
                </Stack>
                : <GrantAccessComponent OnCancel={() => setGrantAccess(false)} OnFinished={() => {setGrantAccess(false); setFinishedAccess(true);}}/>}
                </Paper>
                
                <Snackbar
                    open={finishedAccess}
                    autoHideDuration={5000}
                    onClose={() => setFinishedAccess(false)}
                    message="This Snackbar will be dismissed in 5 seconds."
                >
                    <Alert
                        onClose={() => setFinishedAccess(false)}
                        severity="success"
                        variant="filled"
                        sx={{ width: '100%' }}
                    >
                        Пароль успешно установлен
                    </Alert>
                </Snackbar>
                <Dialog
                    open={showDialog}
                    TransitionComponent={Transition}
                    aria-describedby="why-auth-dialog-descr"
                    keepMounted             
                >
                    <DialogTitle>Зачем требуется авторизация?</DialogTitle>
                    <Divider />
                    <DialogContent>
                        <DialogContentText id='why-auth-dialog-descr'>
                            Авторизация требуется для ограничения доступа к веб-приложению извне.<br/><br/>
                            Приложение не является официальным (не разработано Lemana PRO) и хранится на личном сервере, поэтому 
                            имеется необходимость в разграничении прав доступа к тем или иным функциям приложения.
                            <br/><br/>
                            Пароли храняться в шифрованном виде, поэтому нет смысла опасаться, что 
                            кто-то будет знать твои данные.
                        </DialogContentText>
                    </DialogContent>
                    <DialogActions>
                        <Button onClick={() => setDialog(false)}>ОК</Button>
                    </DialogActions>
                </Dialog>
        </Grid2>
    )

}