import { Card, CardContent, Container, Grid2, Typography } from "@mui/material";
import { BarChart } from '@mui/x-charts/BarChart';
import { CreateSellChart } from "./Components/Charts/CreateSellChart";
import { useEffect, useState } from "react";
import API from "../../API/API";
import { ValueChartData } from "./Components/Charts/ValueChartData";
import { RemainsTotalSizeChart } from "./Components/Charts/RemainsTotalSizeChart";
import { RemainsNotSelledBySize } from "./Components/Charts/RemainsNotSelledBySize";
import { RemainsLifeTime } from "./Components/Charts/RemainsLifeTime";


export function ChartsPage(props) {

    const [SellCreate,setSellCreate] = useState(null);
    const [TotalRemains,setTotal] = useState(null);
    const [CountBySize,setSizeCounter] = useState(null);
    const [LifeTime,setLifeTime] = useState(null);

    useEffect(() => {
        (async () => {
            let result = await API.RequestChartsData();
            setSellCreate(result.CreateSellData);
            setTotal(result.TotalNotSale);
            setSizeCounter(result.CountBySize);
            setLifeTime(result.LiveTimeBySize);
        })();
    },[]);

    return (
        <Container fixed>
            <Grid2 columns={12} container padding={1} spacing={1}>
                <Grid2 size={12}>
                    <Card variant="outlined">
                        <CardContent>
                        <Typography variant="h4">
                            Что это за страница?
                        </Typography>
                        <Typography variant="body1">
                            Данная страница показывает статистику по остаткам.<br/>
                            Здесь можно узнать какие размеры быстрее продаются, динамику остатков и т.п.
                        </Typography>
                        </CardContent>
                    </Card>
                </Grid2>
                <Grid2 size={{xs: 12, sm: 12, md: 12, lg: 12}}>
                    <ValueChartData label="Всего остатков" data={TotalRemains} />
                </Grid2>
                <Grid2 size={{xs: 12, sm: 12, md: 6, lg: 6}}>
                    <CreateSellChart data={SellCreate} />
                </Grid2>
                <Grid2 size={{xs: 12, sm: 12, md: 6, lg: 6}}>
                    <RemainsTotalSizeChart data={CountBySize} />
                </Grid2>
                <Grid2 size={{xs: 12, sm: 12, md: 6, lg: 6}}>
                    <RemainsNotSelledBySize data={CountBySize} />
                </Grid2>
                <Grid2 size={{xs: 12, sm: 12, md: 6, lg: 6}}>
                    <RemainsLifeTime data={LifeTime} />
                </Grid2>
            </Grid2>
        </Container>
    )
}