import axios from "axios";
import Cookies from "universal-cookie";
import axiosRetry from "axios-retry";

//const API_URL = "http://188.234.213.17:5250/api"
const API_URL = "https://a29692-bf32.t.d-f.pw/api"




export default new class API {

    SendFeedback(text) {
        return new Promise((resolve,reject) => {
            axios.post(
                `${API_URL}/users/feedback`,
                {
                    feedback: text
                }
            ).then(response => {
                if(response.status == 200) {
                    resolve();
                }
                else reject();
            }).catch(e => {
                reject(e)
            });
        });
    }

    RequestChartsData() {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/remains/v2/getStats`
            ).then(response => {
                    if(response.status == 200) {
                        resolve(response.data);
                    }
                    else {
                        reject(response.status);
                    }
                }
            ).catch(e => {
                console.log(e);
                reject();
            })
        });
    }

    RequestSendPrint() {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/remains/get?unprinted=1`
            ).then(response => {
                if(response.status == 200) {
                    resolve(response.data);
                }
                else {
                    reject();
                }
            }).catch(e => {
                reject();
            })
        });
    }

    RequestUnprinted() {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/remains/get?unprinted=1`
            ).then(response => {
                if(response.status == 200) {
                    resolve(response.data);
                }
                else {
                    reject();
                }
            }).catch(e => {
                reject();
            })
        });
    }

    RemoveRemain(id) {
        axios.get(
            `${API_URL}/remains/remove?id=${id}`);
    }

    AddNewItem(item) {
        return new Promise((resolve,reject) => {
            axios.post(
                `${API_URL}/items/add`,
                {
                    item: item
                }
            ).then(res => {
                resolve(true);
            }).catch(e => {
                reject();
            }).finally(() => {
            });
        })
    }

    PostNewRemains(remainsList) {
        return new Promise((resolve,reject) => {
            axios.post(
                `${API_URL}/remains/add`,
                {items: remainsList}
            ).then(data => {
                if(data.status == 200) {
                    resolve(data.data);
                }
                else {
                    reject(data.status);
                }
            }).catch(e => {
                reject(e);
            });
        })
    }

    RequestPasswordReset(phone) {
        return new Promise((resolve,reject) => {
            axios.post(
                `${API_URL}/auth/v2/request`,
                {
                    phone: phone
                }
            ).then(response => {
                if(response.status === 200) {
                    let data = response.data;
                    if(data.NeedReset) {
                        resolve(data);
                    }
                    else {
                        reject("ALREADY_RESETED");
                    }
                }
                else {
                    reject(response.status);
                }
            }).catch(e => {
                reject("INTERNAL");
            })
        });
    }

    ResetPassword(changeCode,newPass) {
        return new Promise((resolve,reject) => {
            axios.post(
                `${API_URL}/auth/v2/changePassword`,
                {
                    changeCode: changeCode,
                    newPass: newPass
                }
            ).then(response => {
                if(response.status === 200) {
                    resolve(response.status);
                }
                else {
                    reject(response.status);
                }
            }).catch(e => {
                reject(e);
            })
        });
    }

    GetItemInfo(lm_code) {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/items/get?lm=${lm_code}`
            ).then((response) => {
                if(response.status == 200) {
                    return resolve(response.data);
                }
                reject();
            }).catch(e => reject(e));
        });
    }

    CheckAuth(onAuthCallback = (username)=> {}) {
        axios.get(
            `${API_URL}/auth/v2/checkAuth`
        ).then(response => {
            if(response.status == 200) {
                onAuthCallback(response.data);
            }
        })
    }

    RequestManifest(onNoConnectionCallback = () => {}) {
        axios.get(`${API_URL}/manifest`,{timeout: 3000}).then(response => {
            if(response.code === "ECONNABORTED") {
                onNoConnectionCallback();
            }
        }).catch(error => {
            onNoConnectionCallback();
        })
    }

    GetItemNames() {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/items/v2/getNames`
            ).then((result) => {
                if(result.status == 200) {
                    resolve(result.data);
                }
                else {
                    reject();
                }
            }).catch(e => {
                reject(e.response.status);
            })
        });
    }

    Auth(phone,password) {
        return new Promise((resolve,reject) => {
            axios.post(
                `${API_URL}/auth/v2/signin`,{
                    phone: phone,
                    password: password
                }
            ).then((result) => {
                
                
                if(result.status == 200) {
                    resolve(result.data);
                }
                else {
                    reject(result.status);
                }
            }).catch(e => {
                reject(e.response.status);
            })
        });
    }

    PrintOneRemain(item) {
        return new Promise((resolve,reject) => {
        axios.post(
            `${API_URL}/remains/printRemains`,
            {
                items: item
            },{
                responseType: 'blob'
            }
        ).then(response => {
            setTimeout(() => 
            resolve(response),3000);
        }).catch(e => {
            reject(e);
        });
     })
    }

    SellRemain(id) {
        return new Promise((resolve,reject) => {
        axios.get(
            `${API_URL}/remains/sell?id=${id}`
        ).then(response => {
            resolve(response);
        }).catch(e => {
            reject(e);
        });
     })
    }

    RefreshTokens(refreshToken) {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/auth/v2/token/refresh?token=${refreshToken}`).then(res => {
                    if(res.status == 200) return resolve(res.data);
                    reject();
                }).catch(e => {
                    reject(e);
                });
        });
    }

    GetUnprintedCount() {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/remains/v2/unprintedcount`
            ).then(response => {
                resolve(response.data.count);
            }).catch(e => {
                reject(e);
            });
        });
    }

    GetRemainList(page = 0) {
        return new Promise((resolve,reject) => {
            axios.get(
                `${API_URL}/remains/v2/get?page=${page}&printed=0`
            ).then(response => {
                resolve(response);
            }).catch(e => {
                reject(e);
            });
        })
    }
}