import { Box, CircularProgress, Paper, Stack, Typography } from "@mui/material"
import { useEffect, useRef, useState } from "react"
import RemainItem from "./RemainItem"
import API from "../../../API/API";

function FetchingLoader(props) {

    return (
        <Box width={'100%'} height={'100%'} justifyContent='center' justifyItems='center' textAlign='center'>
            <CircularProgress />
            <Typography>
                Загрузка данных...
            </Typography>
        </Box>
    );
}

var searchTimer;

export default function RemainList({onItemClick,filterText,...props}) {

    var page = 0;
    
    const listElement = useRef(null);
    const [remains,setRemains] = useState([])
    const [filtered,setFiltered] = useState([]);
    const [fetching,setFetching] = useState(false);

    const handleScroll = (current) => {
        if(current.target.scrollHeight == current.target.clientHeight+current.target.scrollTop && !fetching) {
            setFetching(true);
            FetchData(page);
        }
    }

    async function FetchData(targetPage) {
        try {
        let data = await API.GetRemainList(targetPage);
        let newData = [...remains];
        let result = newData.concat(data.data.data);
        setRemains(result);
        setFiltered(result);
        }
        catch(e) {
            
        }
    }

    useEffect(() => {
        FetchData();
    },[]);

    

    useEffect(() => {
        let result = remains.filter(d => d.Name.toLowerCase().includes(filterText.toLowerCase()));
        setFiltered(result);
    },[filterText])


    return (
        <Paper ref={listElement} variant="outlined" sx={{ height:'75vh', overflowX: 'none', overflowY:'auto'}}>
                            <Stack direction="column" spacing={0.2}>
                            {remains.length > 0 ? (filtered.map((item,index) => 
                                <RemainItem key={index} item={item} onClick={(item) => onItemClick(item)}/>
                            )) : <FetchingLoader />}
                            </Stack>
        </Paper>
    )
}