import { Box, Card, CardContent, CircularProgress, Typography } from "@mui/material";
import { BarChart } from "@mui/x-charts";
import { useEffect } from "react"

const monthNames = [
    "Январь",
    "Февраль",
    "Март",
    "Апрель",
    "Май",
    "Июнь",
    "Июль",
    "Август",
    "Сентябрь",
    "Октябрь",
    "Ноябрь",
    "Декабрь",
];

export function CreateSellChart({data,...props}) {

    useEffect(() => {
    },[data]);

    return (
        <Card variant="outlined">
                        <CardContent>
        <Typography variant="h5">
            Соотношение создано-продано 2024г.
        </Typography>
        {data == null ? <Box sx={{minHeight: "300px"}} display="flex-column" justifyItems="center" alignContent="center">
            <CircularProgress />
            <Typography variant="h6">
                Загружаю данные...
            </Typography>
        </Box>
        :
        <BarChart 
                                xAxis={[{scaleType: 'band', data: data.map(d => d.Month)}]}
                                series={[
                                    {data: data.map(d => d.Selled), label: 'Продано', color:'#008800'},
                                    {data: data.map(d => d.Created), label: 'Создано', color:'#ccaa00'}
                                ]}
                                height={300}
                                borderRadius={10}
        />}
        </CardContent>
        </Card>
    )
}