import { Alert, AlertTitle, Box, Button, Collapse, Container, Dialog, DialogActions, DialogContent, DialogTitle, Divider, Grid2, Link, TextField, Toolbar } from "@mui/material";
import MenuBar from "../../GlobalComponents/MenuBar";
import MenuButton from "./Components/MenuBtn";
import { useState } from "react";
import API from "../../API/API";

const MenuButtons = [
    {to:"/remains",img:"https://cdn-icons-png.flaticon.com/512/80/80729.png",label:"Работа с остатками"},
    {to:"/mixes",img:"https://cdn-icons-png.flaticon.com/512/814/814990.png",label:"Работа с микс-паллетами"},
    {to:"/orders",img:"https://cdn-icons-png.flaticon.com/512/5218/5218542.png",label:"Контроль заказов"},
    {to:"/nightTasks",img:"https://cdn-icons-png.flaticon.com/512/1440/1440785.png",label:"Ночные задания"}
]



export default function MainMenuPage() {

    const [showChangelog,setChangelog] = useState(false);
    const [showOS,setOS] = useState(false);
    
    
    const [feedbackText,setFeedbackText] = useState("");
    const [feedbackError,setFeedbackError] = useState("");

    const HandleSendFeedback = () => {
        if(feedbackText.length <= 0) {
            setFeedbackError("Нельзя отправить пустой текст");
            return;
        }
        API.SendFeedback(feedbackText).then(() => {
         setOS(false);
        }).catch(() => {
            setFeedbackError("Что-то пошло не так. Попробуй еще раз, либо попробуй позже");
        })
    }

    return (
        <>
            <Container>
            <Grid2 
                padding={2}
                spacing={2}
                container
                direction="row"
                columns={12}>
                    {MenuButtons.map((button,index) => (
                    <Grid2 key={index} size={{xs: 6, sm: 6, md: 3}}>
                        <MenuButton to={button.to} img={button.img} label={button.label} />
                    </Grid2>
                    ))}
            </Grid2>

            <Box padding={2}>
                <Alert severity="info">
                    <AlertTitle>Веб-приложение обновлено</AlertTitle>
                    Узнать, что было добавлено, можно <Link href="#changelog" onClick={()=>setChangelog(true)} color='inherit'>здесь</Link>.<br/>
                    <br/>
                    Если есть предложение, замечания - воспользуйся <Link href="#os" onClick={() => setOS(true)} color='inherit'>обратной связью</Link>.
                </Alert>
            </Box>
            </Container>
            <Dialog
                fullWidth
                open={showChangelog}
                onClose = {()=>setChangelog(false)}
            >
                <DialogTitle>
                    Что нового?
                </DialogTitle>
                <Divider />
                <DialogContent>
                    <b>Новое:</b>
                    <ul>
                        <li>Новый интерфейс с нацеленностью на мобильные платформы</li>
                        <li>Добавлено отображение оверлока в списке остатков</li>
                        <li>Теперь отображается создатель остатка</li>
                        <li>Теперь в списке остатков можно сразу проверить цену</li>
                        <li>Оверлок теперь отображается в "Создание остатков"</li>
                    </ul>
                </DialogContent>
                <DialogActions>
                    <Button onClick={() => setChangelog(false)} >Закрыть</Button>
                </DialogActions>
            </Dialog>

            <Dialog
                fullWidth
                open={showOS}
                onClose = {()=>setOS(false)}
            >
                <DialogTitle>
                    Обратная связь
                </DialogTitle>
                <Divider />
                <DialogContent>
                    Здесь ты можешь отправить обратную связь по данному инструменту: что добавить, что исправить, что не удобно, предложения как сделать удобнее и тому подобное
                    <br/>
                    <br/>
                    <Collapse in={feedbackError.length > 0}>
                        <Alert severity="error">
                            {feedbackError}
                        </Alert>
                    </Collapse>
                    <TextField minRows={4} maxRows={6} label="Обратная связь" multiline fullWidth value={feedbackText} onChange={(e) => setFeedbackText(e.target.value)}/>
                </DialogContent>
                <DialogActions>
                    <Button onClick={() => setOS(false)} color='secondary'>Закрыть</Button>
                    <Button onClick={HandleSendFeedback} >Отправить</Button>
                </DialogActions>
            </Dialog>
        </>
    );
}